import { Component, OnInit } from '@angular/core';
import { MaintenanceService } from '../../services/maintenance.service';
import { AuthService } from '../../services/auth.service';
import { MaintenanceRequest } from '../../models/maintenance-request.model';

@Component({
  selector: 'app-maintenance',
  templateUrl: './maintenance.component.html',
  styleUrls: ['./maintenance.component.css']
})
export class MaintenanceComponent implements OnInit {
  requests: MaintenanceRequest[] = [];
  currentUser: any;
  showForm = false;
  newRequest: MaintenanceRequest = { studentId: 0, studentName: '', roomId: 0, roomNumber: '', issueType: '', description: '', status: 'PENDING', priority: 'MEDIUM' };

  constructor(private maintenanceService: MaintenanceService, private authService: AuthService) {}

  ngOnInit() {
    this.currentUser = this.authService.getCurrentUser();
    this.loadRequests();
  }

  loadRequests() {
    if (this.currentUser.role === 'STUDENT') {
      this.maintenanceService.getMaintenanceRequestsByStudent(this.currentUser.id).subscribe(data => this.requests = data);
    } else {
      this.maintenanceService.getAllMaintenanceRequests().subscribe(data => this.requests = data);
    }
  }

  createRequest() {
    this.newRequest.studentId = this.currentUser.id;
    this.newRequest.studentName = this.currentUser.firstName + ' ' + this.currentUser.lastName;
    this.newRequest.roomId = this.currentUser.roomId || 0;
    this.maintenanceService.createMaintenanceRequest(this.newRequest).subscribe(() => {
      this.loadRequests();
      this.showForm = false;
      alert('Maintenance request submitted!');
    });
  }
}
<div class="content-wrapper">
  <div class="container-fluid">
    <div class="d-flex justify-content-between mb-4">
      <h2>Maintenance Requests</h2>
      <button class="btn btn-primary" *ngIf="currentUser?.role === 'STUDENT'" (click)="showForm = !showForm">
        {{ showForm ? 'Cancel' : '+ New Request' }}
      </button>
    </div>

    <div *ngIf="showForm" class="card mb-4">
      <div class="card-body">
        <form (ngSubmit)="createRequest()">
          <div class="row">
            <div class="col-md-6 mb-3">
              <label class="form-label">Issue Type</label>
              <input type="text" class="form-control" [(ngModel)]="newRequest.issueType" name="issueType" required>
            </div>
            <div class="col-md-6 mb-3">
              <label class="form-label">Room Number</label>
              <input type="text" class="form-control" [(ngModel)]="newRequest.roomNumber" name="roomNumber" required>
            </div>
          </div>
          <div class="mb-3">
            <label class="form-label">Description</label>
            <textarea class="form-control" [(ngModel)]="newRequest.description" name="description" rows="3" required></textarea>
          </div>
          <div class="mb-3">
            <label class="form-label">Priority</label>
            <select class="form-control" [(ngModel)]="newRequest.priority" name="priority">
              <option value="LOW">Low</option>
              <option value="MEDIUM">Medium</option>
              <option value="HIGH">High</option>
              <option value="URGENT">Urgent</option>
            </select>
          </div>
          <button type="submit" class="btn btn-success">Submit Request</button>
        </form>
      </div>
    </div>

    <div class="table-responsive">
      <table class="table">
        <thead>
          <tr>
            <th>ID</th>
            <th>Student</th>
            <th>Room</th>
            <th>Issue Type</th>
            <th>Priority</th>
            <th>Status</th>
            <th>Created</th>
          </tr>
        </thead>
        <tbody>
          <tr *ngFor="let req of requests">
            <td>{{ req.id }}</td>
            <td>{{ req.studentName }}</td>
            <td>{{ req.roomNumber }}</td>
            <td>{{ req.issueType }}</td>
            <td><span class="badge" [ngClass]="{'bg-danger': req.priority === 'URGENT', 'bg-warning': req.priority === 'HIGH', 'bg-info': req.priority === 'MEDIUM', 'bg-secondary': req.priority === 'LOW'}">
              {{ req.priority }}</span></td>
            <td><span class="badge" [ngClass]="{'bg-success': req.status === 'RESOLVED', 'bg-warning': req.status === 'PENDING', 'bg-primary': req.status === 'IN_PROGRESS'}">
              {{ req.status }}</span></td>
            <td>{{ req.createdAt | date:'short' }}</td>
          </tr>
        </tbody>
      </table>
    </div>
  </div>
</div>
